import axios from 'axios';

const api = axios.create({
  baseURL: 'http://localhost:5000/api', // Maps to backend
});

api.interceptors.request.use((config) => {
  const token = localStorage.getItem('accessToken');
  if (token) config.headers.Authorization = `Bearer ${token}`;
  return config;
});

api.interceptors.response.use(
  (response) => response,
  (error) => {
    // Standardize error message extraction
    const message = error.response?.data?.message || error.message || 'An unexpected error occurred';
    const statusCode = error.response?.status || 500;
    const errors = error.response?.data?.errors || null;

    if (statusCode === 401) {
      localStorage.removeItem('accessToken');
      window.dispatchEvent(new Event('auth:logout'));
    }

    return Promise.reject({ message, statusCode, errors });
  }
);

// Unified Exports
export const authAPI = {
  register: (data) => api.post('/auth/register', data),
  login: (data) => api.post('/auth/login', data),
  getMe: () => api.get('/auth/me'),
  logout: () => api.post('/auth/logout').finally(() => localStorage.removeItem('accessToken'))
};

export const booksAPI = { getAll: () => api.get('/books') };
export const libraryCardsAPI = { apply: (data) => api.post('/library-cards/apply', data), getMyCard: () => api.get('/library-cards/my-card'), getAll: () => api.get('/library-cards') };
export const issuesAPI = { getAll: () => api.get('/issues'), issueBook: (data) => api.post('/issues/issue', data), returnBook: (data) => api.post('/issues/return', data) };
export const finesAPI = { getAll: () => api.get('/fines'), getMyFines: () => api.get('/fines/my-fines') };

export default api;
